from config.settings import settings

class MemoryManager:
    """
    Controller for the game's memory.
    Ensures the data stays relevant and within the LLM's token limits.
    """

    def __init__(self, memory_model: Memory):
        #We pass the raw data model into this manager.
        self.memory = memory_model

    def log_choice(self, choice: str):
        """Logs a player's choice and enforces the history limit."""
        self.memory.record_choice(choice)

        #If we exceed the max history, remove the oldest item (FIFO)
        if len(self.memory.past_choices) > settings.MAX_MEMORY_HISTORY:
            self.memory.past_choices.pop(0)

    def log_event(self, event: str):
        """Logs a significant event and enforces the history limit."""
        self.memory.record_event(event)

        # If we exceed the max history, remove the oldest item (FIFO)
        if len(self.memory.key_events) > settings.MAX_MEMORY_HISTORY:
            self.memory.key_events.pop(0)

    def adjust_relationship(self, character_name: str, score_change: int):
        """Updates how an NPC feels about the player."""
        if score_change != 0:
            self.memory.update_relationship(character_name, score_change)

    def get_llm_context(self) -> str:
        """Fetches the formatted, token-safe context string for the LLM."""
        return self.memory.get_context_summary(max_items=settings.MAX_MEMORY_HISTORY)

from dataclasses import dataclass, field
from typing import List, Dict

@dataclass
class Memory:
    """Tracks player decisions, relationships, and key events for LLM context."""
    past_choices: List[str] = field(default_factory=list)
    key_events: List[str] = field(default_factory=list)
    relationships: Dict[str, int] = field(default_factory=dict)

    def record_choice(self, choice: str):
        """Logs a choice made by the player."""
        self.past_choices.append(choice)

    def record_event(self, event: str):
        """Logs a significant story event."""
        self.key_events.append(event)

    def update_relationship(self, character_name: str, score_change: int):
        """Updates the relationship score with a specific NPC."""
        if character_name not in self.relationships:
            self.relationships[character_name] = 0

        self.relationships[character_name] += score_change

    def get_context_summary(self, max_items: int = 5) -> str:
        """Formats the memory into a concise string to inject into the LLM prompt."""
        context_parts = []

        if self.key_events:
            #Grab only the most recent events to save tokens
            recent_events = self.key_events[-max_items:]
            context_parts.append("Key Events: " + ", ".join(recent_events))

        if self.past_choices:
            recent_choices = self.past_choices[-max_items:]
            context_parts.append("Recent Choices: " + ", ".join(recent_choices))

        if self.relationships:
            rels = [f"{char} ({score})" for char, score in self.relationships.items()]
            context_parts.append(f"Relationships: {', '.join(rels)}")

        if not context_parts:
            return "No significant history yet."

        return " | ".join(context_parts)

    def to_dict(self) -> dict:
        """Converts memory to a dictionary for saving."""
        return{
            "past_choices": self.past_choices,
            "key_events": self.key_events,
            "relationships": self.relationships
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'Memory':
        """Creates a Memory instance from a dictionary (loading)"""
        return cls(
            past_choices = data.get("past_choices", []),
            key_events = data.get("key_events", []),
            relationships = data.get("relationships", {})
        )

from dataclasses import dataclass, field
from typing import List

@dataclass
class Player:
    """Represents the user's character in the story."""
    name: str
    alignment: str = "neutral"
    alignment_score: int = 0
    traits: List[str] = field(default_factory=list)

    def update_alignment(self, score_change: int):
        """Updates the player's alignment score and categorizes them."""
        self.alignment_score += score_change

        #Clamp the score between -100 and 100
        self.alignment_score = max(-100, min(100, self.alignment_score))

        #Update the categorical alignment
        if self.alignment_score >=20:
            self.alignment = "heroic"
        elif self.alignment_score <= -20:
            self.alignment = "villainous"
        else:
            self.alignment = "neutral"

    def add_trait(self, trait: str):
        """Adds a personality trait or title to the player."""
        if trait not in self.traits:
            self.traits.append(trait)

    def to_dict(self) -> dict:
        """Converts the player object to a dictionary for saving"""
        return{
            "name": self.name,
            "alignment": self.alignment,
            "alignment_score": self.alignment_score,
            "traits": self.traits
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'Player':
        """Creates a Player instance from a dictionary (loading)."""
        return cls(
            name=data.get("name", "Wanderer"),
            alignment=data.get("alignment", "neutral"),
            alignment_score=data.get("alignment_score", 0),
            traits=data.get("traits", [])
        )

from dataclasses import dataclass, field
from typing import List

@dataclass
class StoryState:
    """Represents the current state and progression of the narrative."""
    current_scene: str = "The story has not yet begun."
    chapter: int = 1
    available_choices: List[str] = field(default_factory=list)
    story_history: List[str] = field(default_factory=list)

    def advance_chapter(self):
        """Increments the chapter counter."""
        self.chapter += 1

    def add_to_history(self, text: str):
        """Appends a completed scene to the overall story history."""
        if text:
            self.story_history.append(text)

    def update_scene(self, new_scene: str, new_choices: List[str]):
        """Updates the current scene and the choices available to the player."""
        self.current_scene = new_scene
        self.available_choices = new_choices

    def to_dict(self) -> dict:
        """Converts the story state to a dictionary for saving."""
        return {
            "current_scene": self.current_scene,
            "chapter": self.chapter,
            "available_choices": self.available_choices,
            "story_history": self.story_history
        }

    @classmethod
    def from_dict(cls, data: dict) -> 'StoryState':
        """Creates a StoryState instance from a dictionary (loading)"""
        return cls(
            current_scene=data.get("current_scene", "The story has not yet begun."),
            chapter=data.get("chapter", 1),
            available_choices=data.get("available_choices", []),
            story_history=data.get("story_history", [])
        )

